import{_ as a,o as i,c as o,ai as l}from"./chunks/framework.CsYGeNYI.js";const p=JSON.parse('{"title":"语音唤醒","description":"","frontmatter":{"read_when":["开发语音唤醒或按键通话路径"],"summary":"Mac 应用中的语音唤醒和按键通话模式及路由详情","title":"语音唤醒","x-i18n":{"generated_at":"2026-02-03T10:08:23Z","model":"claude-opus-4-5","provider":"pi","source_hash":"f6440bb89f349ba5c1c9aacffe95e568681beb9899ca736dedfe2f4a366cb5e4","source_path":"platforms/mac/voicewake.md","workflow":15}},"headers":[],"relativePath":"zh-CN/platforms/mac/voicewake.md","filePath":"zh-CN/platforms/mac/voicewake.md","lastUpdated":1771906665000}'),r={name:"zh-CN/platforms/mac/voicewake.md"};function c(t,e,d,s,n,h){return i(),o("div",null,[...e[0]||(e[0]=[l('<h1 id="语音唤醒与按键通话" tabindex="-1"><a class="header-anchor" href="#语音唤醒与按键通话">#</a> 语音唤醒与按键通话</h1><h2 id="模式" tabindex="-1"><a class="header-anchor" href="#模式">#</a> 模式</h2><ul><li><strong>唤醒词模式</strong>（默认）：常驻语音识别器等待触发词（<code>swabbleTriggerWords</code>）。匹配时开始捕获，显示带有部分文本的悬浮窗，并在静默后自动发送。</li><li><strong>按键通话（按住右 Option 键）</strong>：按住右 Option 键立即开始捕获——无需触发词。按住时显示悬浮窗；松开后延迟片刻再最终转发，以便你可以调整文本。</li></ul><h2 id="运行时行为-唤醒词" tabindex="-1"><a class="header-anchor" href="#运行时行为-唤醒词">#</a> 运行时行为（唤醒词）</h2><ul><li>语音识别器位于 <code>VoiceWakeRuntime</code> 中。</li><li>仅当唤醒词和下一个词之间有<strong>明显停顿</strong>（约 0.55 秒间隔）时才触发。悬浮窗/提示音可以在命令开始前的停顿时就启动。</li><li>静默窗口：语音流畅时为 2.0 秒，如果只听到触发词则为 5.0 秒。</li><li>硬性停止：120 秒，防止会话失控。</li><li>会话间去抖动：350 毫秒。</li><li>悬浮窗通过 <code>VoiceWakeOverlayController</code> 驱动，带有已提交/临时状态的颜色区分。</li><li>发送后，识别器干净地重启以监听下一个触发词。</li></ul><h2 id="生命周期不变量" tabindex="-1"><a class="header-anchor" href="#生命周期不变量">#</a> 生命周期不变量</h2><ul><li>如果启用了语音唤醒且权限已授予，唤醒词识别器应该处于监听状态（除非正在进行显式的按键通话捕获）。</li><li>悬浮窗可见性（包括通过 X 按钮手动关闭）绝不能阻止识别器恢复。</li></ul><h2 id="悬浮窗卡住的故障模式-之前的问题" tabindex="-1"><a class="header-anchor" href="#悬浮窗卡住的故障模式-之前的问题">#</a> 悬浮窗卡住的故障模式（之前的问题）</h2><p>之前，如果悬浮窗卡在可见状态且你手动关闭它，语音唤醒可能会显得&quot;失效&quot;，因为运行时的重启尝试可能被悬浮窗可见性阻止，且没有安排后续重启。</p><p>加固措施：</p><ul><li>唤醒运行时重启不再被悬浮窗可见性阻止。</li><li>悬浮窗关闭完成时通过 <code>VoiceSessionCoordinator</code> 触发 <code>VoiceWakeRuntime.refresh(...)</code>，因此手动点击 X 关闭总是会恢复监听。</li></ul><h2 id="按键通话细节" tabindex="-1"><a class="header-anchor" href="#按键通话细节">#</a> 按键通话细节</h2><ul><li>热键检测使用全局 <code>.flagsChanged</code> 监视器检测<strong>右 Option 键</strong>（<code>keyCode 61</code> + <code>.option</code>）。我们只观察事件（不拦截）。</li><li>捕获管道位于 <code>VoicePushToTalk</code> 中：立即启动语音识别，将部分结果流式传输到悬浮窗，并在松开时调用 <code>VoiceWakeForwarder</code>。</li><li>按键通话开始时，我们暂停唤醒词运行时以避免音频采集冲突；松开后自动重启。</li><li>权限：需要麦克风 + 语音识别权限；查看事件需要辅助功能/输入监控批准。</li><li>外接键盘：某些键盘可能无法按预期暴露右 Option 键——如果用户报告未响应，提供备用快捷键。</li></ul><h2 id="面向用户的设置" tabindex="-1"><a class="header-anchor" href="#面向用户的设置">#</a> 面向用户的设置</h2><ul><li><strong>语音唤醒</strong>开关：启用唤醒词运行时。</li><li><strong>按住 Cmd+Fn 说话</strong>：启用按键通话监视器。在 macOS &lt; 26 上禁用。</li><li>语言和麦克风选择器、实时电平指示器、触发词表、测试器（仅本地；不转发）。</li><li>麦克风选择器在设备断开时保留上次选择，显示断开提示，并临时回退到系统默认设备直到设备恢复。</li><li><strong>声音</strong>：触发检测和发送时的提示音；默认为 macOS&quot;Glass&quot;系统声音。你可以为每个事件选择任何 <code>NSSound</code> 可加载的文件（例如 MP3/WAV/AIFF）或选择<strong>无声音</strong>。</li></ul><h2 id="转发行为" tabindex="-1"><a class="header-anchor" href="#转发行为">#</a> 转发行为</h2><ul><li>启用语音唤醒时，转录文本被转发到活动的 Gateway 网关/智能体（与 Mac 应用其他部分使用相同的本地/远程模式）。</li><li>回复被投递到<strong>上次使用的主提供商</strong>（WhatsApp/Telegram/Discord/WebChat）。如果投递失败，错误会被记录，运行记录仍可通过 WebChat/会话日志查看。</li></ul><h2 id="转发负载" tabindex="-1"><a class="header-anchor" href="#转发负载">#</a> 转发负载</h2><ul><li><code>VoiceWakeForwarder.prefixedTranscript(_:)</code> 在发送前添加机器提示前缀。唤醒词和按键通话路径共享此方法。</li></ul><h2 id="快速验证" tabindex="-1"><a class="header-anchor" href="#快速验证">#</a> 快速验证</h2><ul><li>开启按键通话，按住 Cmd+Fn，说话，松开：悬浮窗应显示部分结果然后发送。</li><li>按住时，菜单栏耳朵图标应保持放大状态（使用 <code>triggerVoiceEars(ttl:nil)</code>）；松开后恢复。</li></ul>',21)])])}const f=a(r,[["render",c]]);export{p as __pageData,f as default};
